#include "i2c_oled.h"
#include <Wire.h>
#include <Adafruit_GFX.h>
static Adafruit_SSD1306 display(128, 64, &Wire, -1);
void oled_setup() {
  Wire.begin();
  if (!display.begin(SSD1306_SWITCHCAPVCC, 0x3C)) {
    Serial.println("[oled] Init failed!"); return;
  }
  display.clearDisplay();
  display.setTextColor(SSD1306_WHITE);
  display.display();
  Serial.println("[oled] OK 128x64");
}
void oled_clear() { display.clearDisplay(); }
void oled_text(int x, int y, const char* t, int s) {
  display.setTextSize(s); display.setCursor(x, y); display.print(t);
}
void oled_update() { display.display(); }
void oled_draw_rect(int x, int y, int w, int h) { display.drawRect(x,y,w,h,SSD1306_WHITE); }
void oled_draw_progress(int x, int y, int w, int h, int pct) {
  display.drawRect(x,y,w,h,SSD1306_WHITE);
  int fill = (w-2) * constrain(pct,0,100) / 100;
  display.fillRect(x+1,y+1,fill,h-2,SSD1306_WHITE);
}
